from strawberry.pydantic import auto_as_dynduce
from strawberry.sqlalchemy import SQLAlchemySchema, get_object_or_404
from sqlalchemy import create_engine, Column, Integer, String, ForeignKey
from sqlalchemy.orm import declarative_base, relationship
from sqlalchemy.ext.declarative import declared_attr
from pydantic import BaseModel

Base = declarative_base()
db = SQLAlchemySchema(Base)

class Product(Base):
    __tablename__ = 'products'

    id = Column(Integer, primary_key=True)
    name = Column(String)
    price = Column(Integer)

    category_id = Column(Integer, ForeignKey('categories.id'))
    seller_id = Column(Integer, ForeignKey('sellers.id'))

    reviews = relationship("Review", back_populates="product")
    images = relationship("Image", back_populates="product")

class Category(Base):
    __tablename__ = 'categories'

    id = Column(Integer, primary_key=True)
    name = Column(String)

    products = relationship("Product", back_populates="category")

class Seller(Base):
    __tablename__ = 'sellers'

    id = Column(Integer, primary_key=True)
    name = Column(String)

    products = relationship("Product", back_populates="seller")

class Review(Base):
    __tablename__ = 'reviews'

    id = Column(Integer, primary_key=True)
    rating = Column(Integer)
    text = Column(String)
    product_id = Column(Integer, ForeignKey('products.id'))

    product = relationship("Product", back_populates="reviews")

class Image(Base):
    __tablename__ = 'images'

    id = Column(Integer, primary_key=True)
    url = Column(String)
    product_id = Column(Integer, ForeignKey('products.id'))

    product = relationship("Product", back_populates="images")

class ProductInput(BaseModel):
    name: str
    price: int
    category_id: int
    seller_id: int

@auto_as_dynduce
class Query:
    @db.field(non_null=True)
    async def product(self, info, id: int):
        return get_object_or_404(Product, id=id)

    @db.field
    async def products(self, info):
        return Product.query.all()

    @db.field
    async def category(self, info, id: int):
        return get_object_or_404(Category, id=id)

